{
  "P0": {
    "site_architecture": [
      "Ensure all pages are indexable and not blocked by robots.txt or noindex tags.",
      "Fix any broken internal links and redirect chains.",
      "Implement a clear silo structure: /tools/, /guides/, /sports/."
    ],
    "technical": [
      "Add structured data (BreadcrumbList, FAQPage, HowTo) to tool pages.",
      "Improve page speed (compress images, minify CSS/JS, enable caching).",
      "Ensure mobile-friendliness and responsive design."
    ],
    "on_page": [
      "Optimize title tags and meta descriptions with primary keywords (e.g., 'Bracket Generator - Free, No Signup').",
      "Add H1 tags with target keywords per page.",
      "Include internal links to related tools and guides."
    ]
  },
  "P1": {
    "topic_authority": [
      "Create a comprehensive 'Tournament Scheduling Guide' hub linking to all tools and guides.",
      "Expand 'Round Robin Generator' page with schedule examples, tie-breaking rules, and printable formats.",
      "Add 'Double Elimination Bracket' page with detailed explanation, seeding, and printable bracket.",
      "Write 'Swiss System Tournament Guide' covering pairing, tie-breaks, and when to use.",
      "Develop 'Playoff Bracket vs Round Robin' comparison page targeting 'tournament format' queries."
    ],
    "avoid_cannibalization": [
      "Merge 'bracket generator' and 'tournament bracket maker' into one canonical page with variants.",
      "Differentiate 'league schedule maker' from 'tournament schedule maker' by audience (recurring vs single event).",
      "Use canonical tags and 301 redirects for duplicate content."
    ]
  },
  "draft_sections": {
    "seeding": "Explain seeding methods (random, snake, merit-based) and provide examples for 8/16/32 teams. Include a table of seeding positions for bracket fairness.",
    "byes": "Define byes, calculate number needed (next power of 2 minus teams), and show placement in bracket. Include a diagram for 5-team bracket.",
    "round_robin": "Describe round-robin scheduling, number of rounds (n-1), and use of circle method. Provide a 4-team schedule table and link to generator.",
    "single_vs_double": "Compare single-elimination (fast, one loss) vs double-elimination (forgiving, more games). Include pros/cons and when to use each.",
    "playoff_bracket": "Explain bracket structure, seeding, and progression. Show a 8-team bracket diagram with matchups and winners path."
  }
}
